@startuml
skinparam shadowing false
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0

package "Switch文を使ったCeilingFan" {
  package "dirty" {

    class App << (C,#B7E1B0) >> {
      {field} {static} {readOnly} STDIN : Scanner
      {field} {static} {readOnly} MSG_PRESS_ENTER : String
      {field} {static} {readOnly} BREAK_LINE : String
      --
      {method} {static} main(String... args) : void
      --
      {method} spendLife(CeilingFanPullChain chain) : void
      {method} show(String message) : void
      {method} recieveInputtedEnterKey() : String
    }

    class CeilingFanPullChain << (C,#B7E1B0) >> {
      {field} currentState : Speed
      --
      {method} CeilingFanPullChain()
      {method} pull() : void
    }

    enum Speed << (E,#F4A582) >> {
      {field} {readOnly} nameJa
      --
      Speed(String nameJa)
      --
      nameJa() : String
      showNameJa() : void
    }

    App ..> CeilingFanPullChain : use
    CeilingFanPullChain ..> Speed : call
  }
}
@enduml
